export const ProtectedRoute = ({ allowedRoles }: ProtectedRouteProps) => {
    const { user, isAuthenticated, isInitializing } = useAuth();
    const location = useLocation();

    if (isInitializing) {
        return (
            <div className="flex h-screen w-screen items-center justify-center bg-[var(--bg-primary)] text-[var(--text-primary)]">
                <div className="text-xl font-medium animate-pulse">Cargando Sistema...</div>
            </div>
        );
    }

    if (!isAuthenticated) {
        return <Navigate to="/login" state={{ from: location }} replace />;
    }

    if (allowedRoles && user && user.role !== Role.SUPERADMIN && !allowedRoles.includes(user.role)) {
        return <Navigate to="/unauthorized" replace />;
    }

    // El onboarding se manejará mediante un modal global en App.tsx
    // para dar más protagonismo y evitar saltos de ruta.

    return <Outlet />;
}

export const RoleGuard = ({ allowedRoles, children, fallback = null }: RoleGuardProps) => {
    const { user, isAuthenticated } = useAuth();

    if (!isAuthenticated || !user) {
        return <>{fallback}</>;
    }

    if (user.role === Role.SUPERADMIN) {
        return <>{children}</>;
    }

    if (!allowedRoles.includes(user.role)) {
        return <>{fallback}</>;
    }

    return <>{children}</>;
};

