  label: string;
  onClick: () => void;
  tone?: 'amber' | 'red' | 'neutral';
}) => {
  const activeStyles =
    tone === 'amber'
      ? {
        background: 'var(--accent-amber-soft)',
        color: 'var(--accent-amber)',
