const Dashboard: React.FC = () => {
  const { data, isLoading, isError } = useDashboard();
  const { data: rackMapData, isLoading: isMapLoading } = useRackMap();
  const { createMovimiento } = useOperaciones();
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  // Mutation para asignar (reemplaza useEmbarcaciones para ser atómico)
  const updateEmbarcacion = useMutation({
    mutationFn: ({ id, data }: { id: number; data: any }) =>
      httpClient.put(`/embarcaciones/${id}`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['dashboard'] });
      queryClient.invalidateQueries({ queryKey: ['embarcaciones'] });
    }
  });

  const [isPagoModalOpen, setIsPagoModalOpen] = useState(false);
  const [is3D, setIs3D] = useState(false);
  const [periodoRecaudacion, setPeriodoRecaudacion] = useState<PeriodoRecaudacion>('mes');
  const [periodoDeuda, setPeriodoDeuda] = useState<PeriodoDeuda>('mes');

const handleAsignarBarco = async (embarcacionId: number, espacioId: number) => {
    try {
      await updateEmbarcacion.mutateAsync({ id: embarcacionId, data: { espacioId } });
      toast.success('Embarcación asignada correctamente');
    } catch (error: any) {
      toast.error(error?.response?.data?.message || 'Error al asignar la embarcación');
    }
  };

  const handleRegistrarSalida = async (embarcacionId: number, tipo: 'entrada' | 'salida' = 'salida') => {
    try {
      await createMovimiento.mutateAsync({ 
        embarcacionId, 
        tipo,
        observaciones: `Registro de ${tipo} desde mapa de racks`
      });
      const msg = tipo === 'salida' ? 'Salida registrada - Embarcación en el agua' : 'Entrada registrada - Embarcación en cuna';
      toast.success(msg);
    } catch (error: any) {
      toast.error(error?.response?.data?.message || `Error al registrar ${tipo}`);
    }
  };

  const stats = data?.stats;
  const embarcacionesLibres = useMemo(() => data?.embarcacionesLibres || [], [data]);

  // Valores de recaudación con fallback al total global si faltan detalles
  const recaudacionValor = useMemo(() => {
    const detalles = stats?.finanzas?.detalles?.recaudacion;
    if (detalles && typeof detalles[periodoRecaudacion] === 'number') {
      return detalles[periodoRecaudacion];
    }
    // Fallback al total global si estamos en periodo mes y faltan detalles
    return periodoRecaudacion === 'mes' ? (stats?.finanzas?.recaudacionTotal ?? 0) : 0;
  }, [stats, periodoRecaudacion]);

  // Valores de deuda con fallback al total global if faltan detalles
  const deudaValor = useMemo(() => {
    const detalles = stats?.finanzas?.detalles?.deuda;
    if (detalles && detalles[periodoDeuda]) {
      return detalles[periodoDeuda].total;
    }
    // Fallback al total global si estamos en periodo mes
    return periodoDeuda === 'mes' ? (stats?.finanzas?.deudaTotal ?? 0) : 0;
  }, [stats, periodoDeuda]);

  if (isLoading) return <DashboardSkeleton />;

  if (isError) {
    return (
      <div className="bento-card p-10 min-h-[420px] flex items-center justify-center">
        <div
          className="rounded-[20px] p-8 text-center max-w-md w-full"
          style={{
            background: 'var(--accent-red-soft)',
            border: '1px solid color-mix(in srgb, var(--accent-red) 18%, transparent)',
          }}
        >
          <h2
            className="text-ui-lg font-bold mb-2"
            style={{ color: 'var(--accent-red)' }}
          >
            Error de conexión
          </h2>
          <p className="text-ui-sm mb-6" style={{ color: 'var(--text-secondary)' }}>
            No se pudo recuperar la información del servidor.
          </p>
          <button
            onClick={() => queryClient.invalidateQueries({ queryKey: ['dashboard'] })}
            className="btn btn-primary"
            style={{ background: 'var(--accent-red)' }}
          >
            Reintentar
          </button>
        </div>
      </div>
    );
  }


  return (
    <>
      <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-700">
        {/* HEADER */}
        <header className="bento-card p-6 md:p-7 relative overflow-hidden">
          <div className="absolute right-6 top-1/2 -translate-y-1/2 pointer-events-none opacity-[0.04] hidden lg:block">
            <Activity className="w-36 h-36" style={{ color: 'var(--accent-purple)' }} />
          </div>

          <div className="relative z-10 flex flex-col lg:flex-row lg:items-center lg:justify-between gap-6">
            <div>
              <div className="flex items-center gap-2 mb-3">
                <span className="relative flex h-2.5 w-2.5">
                  <span
                    className="absolute inline-flex h-full w-full animate-ping rounded-full opacity-60"
                    style={{ backgroundColor: 'var(--accent-teal)' }}
                  />
                  <span
                    className="relative inline-flex h-2.5 w-2.5 rounded-full"
                    style={{ backgroundColor: 'var(--accent-teal)' }}
                  />
                </span>
              </div>

              <h1
                className="text-[28px] md:text-[32px] font-bold leading-none tracking-tight"
                style={{ color: 'var(--text-primary)' }}
              >
                Panel de control
              </h1>

              <p className="text-ui-base mt-3 max-w-2xl" style={{ color: 'var(--text-secondary)' }}>
                Vista integral de infraestructura, flota, recaudación y actividad operativa.
              </p>
            </div>

            <div className="flex flex-col sm:flex-row sm:items-center gap-3">
              <RoleGuard allowedRoles={[Role.ADMIN, Role.SUPERADMIN]}>
                <button
                onClick={() => setIsPagoModalOpen(true)}
                className="btn"
                style={{
                  background: 'linear-gradient(135deg, #1D9E75, #0F6E56)',
                  color: '#E1F5EE',
                }}
              >
                <CreditCard size={15} />
                Registrar pago
              </button>
              </RoleGuard>

              <button
                onClick={() => navigate('/operaciones')}
                className="btn"
                style={{
                  background: 'linear-gradient(135deg, #534AB7, #3C3489)',
                  color: '#EEEDFE',
                }}
              >
                <PlusCircle size={15} />
                Nueva operación
              </button>
            </div>
          </div>
        </header>

        {/* KPI CARDS */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
          <StatCard
            accent="teal"
            title="Cartera global de clientes"
            value={stats?.totalClientes ?? 0}
            icon={<Users size={18} style={{ color: 'var(--accent-teal)' }} />}
            description="Unidades de negocio activas"
          />

          <StatCard
            accent="purple"
            title="Flota estacionaria"
            value={stats?.totalBarcos ?? 0}
            icon={<Ship size={18} style={{ color: 'var(--accent-purple)' }} />}
            subValue={`${stats?.ocupacion?.enAgua ?? 0} a flote · ${stats?.ocupacion?.enCuna ?? 0} guardados`}
          />

          <StatCard
            accent="amber"
            title="Recaudación"
            value={`${(recaudacionValor).toLocaleString()}`}
            icon={<Wallet size={18} style={{ color: 'var(--accent-amber)' }} />}
            description={
              <div className="flex flex-wrap gap-2">
                {(['dia', 'semana', 'mes'] as PeriodoRecaudacion[]).map((p) => (
                  <ToggleChip
                    key={p}
                    label={p === 'dia' ? 'Hoy' : p === 'semana' ? 'Semana' : 'Mes'}
                    active={periodoRecaudacion === p}
                    onClick={() => setPeriodoRecaudacion(p)}
                    tone="amber"
                  />
                ))}
              </div>
            }
          />

          <StatCard
            accent="red"
            title="Cuentas por cobrar"
            value={`${(deudaValor).toLocaleString()}`}
            icon={<ClipboardList size={18} style={{ color: 'var(--accent-red)' }} />}
            description={
              <div className="flex flex-wrap gap-2">
                {(['dia', 'semana', 'mes', 'vencido'] as PeriodoDeuda[]).map((p) => (
                  <ToggleChip
                    key={p}
                    label={
                      p === 'dia'
                        ? 'Hoy'
                        : p === 'semana'
                          ? 'Semana'
                          : p === 'mes'
                            ? 'Mes'
                            : 'Vencido'
                    }
                    active={periodoDeuda === p}
                    onClick={() => setPeriodoDeuda(p)}
                    tone="red"
                  />
                ))}
              </div>
            }
          />
        </div>

        {/* CHART + ACTIVITY */}
        <div className="grid grid-cols-1 xl:grid-cols-3 gap-4">
          <div className="xl:col-span-2 bento-card p-6">
            <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-4 mb-6">
              <div>
                <p className="section-title">Rendimiento financiero</p>
                <p className="text-ui-sm mt-1" style={{ color: 'var(--text-secondary)' }}>
                  Evolución de recaudación.
                </p>
              </div>

              <span className="badge badge-info">ARS</span>
            </div>

            <div className="h-[320px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={data?.graficos.finanzas}>
                  <defs>
                    <linearGradient id="colorMonto" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#1D9E75" stopOpacity={0.22} />
                      <stop offset="95%" stopColor="#1D9E75" stopOpacity={0} />
                    </linearGradient>
                  </defs>

                  <CartesianGrid
                    strokeDasharray="3 3"
                    stroke="var(--border-primary)"
                    vertical={false}
                    strokeOpacity={0.5}
                  />

                  <XAxis
                    dataKey="mes"
                    stroke="var(--text-muted)"
                    fontSize={11}
                    tickLine={false}
                    axisLine={false}
                    dy={10}
                  />

                  <YAxis
                    stroke="var(--text-muted)"
                    fontSize={11}
                    tickLine={false}
                    axisLine={false}
                    tickFormatter={(v) => `$${v / 1000}K`}
                    dx={-8}
                  />

                  <Tooltip
                    cursor={{
                      stroke: 'var(--accent-teal)',
                      strokeWidth: 1,
                      strokeDasharray: '4 4',
                    }}
                    contentStyle={{
                      backgroundColor: 'var(--bg-secondary)',
                      border: '1px solid var(--border-primary)',
                      borderRadius: '16px',
                      padding: '12px 14px',
                      boxShadow: 'var(--shadow-md)',
                    }}
                    itemStyle={{
                      color: 'var(--accent-teal)',
                      fontWeight: 600,
                      fontSize: 13,
                    }}
                    labelStyle={{
                      color: 'var(--text-secondary)',
                      fontSize: 11,
                      marginBottom: 6,
                    }}
                  />

                  <Area
                    type="monotone"
                    dataKey="monto"
                    stroke="var(--accent-teal)"
                    strokeWidth={2.5}
                    fillOpacity={1}
                    fill="url(#colorMonto)"
                    animationDuration={1200}
                    activeDot={{
                      r: 5,
                      strokeWidth: 0,
                      fill: 'var(--accent-teal)',
                    }}
                  />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="bento-card p-5 flex flex-col">
            <div className="flex items-center justify-between mb-5">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="relative flex h-2.5 w-2.5">
                    <span
                      className="absolute inline-flex h-full w-full animate-ping rounded-full opacity-60"
                      style={{ backgroundColor: 'var(--accent-teal)' }}
                    />
                    <span
                      className="relative inline-flex h-2.5 w-2.5 rounded-full"
                      style={{ backgroundColor: 'var(--accent-teal)' }}
                    />
                  </span>
                  <h3 className="section-title">Situación en vivo</h3>
                </div>
                <p className="text-ui-sm" style={{ color: 'var(--text-secondary)' }}>
                  Eventos y alertas recientes
                </p>
              </div>

              <RoleGuard allowedRoles={[Role.ADMIN, Role.SUPERADMIN]}>
                <button
                onClick={() => navigate('/configuracion')}
                className="icon-button"
                title="Configuración"
