                      background: 'linear-gradient(135deg, #534AB7, #3C3489)',
                      color: '#EEEDFE',
                      borderColor: 'transparent',
                    }
                    : undefined
                }
              >
                <Activity size={14} className={is3D ? 'animate-pulse' : ''} />
                Vista 3D {is3D ? 'activa' : 'inactiva'}
