        n.mensaje?.includes(factura.numero) || n.titulo?.includes(factura.numero)
      );
      setAuditLogs(logs);
    } catch (error) {
      console.error('Error fetching audit logs:', error);
    } finally {
      setIsLoadingAudit(false);
    }
  }, [factura.numero]);

  useEffect(() => {
    if (activeTab === 'audit') {
      fetchAuditLogs();
    }
  }, [activeTab, fetchAuditLogs]);

  const downloadPdf = async () => {
