      const blob = await httpClient.get<Blob>(`/facturas/${factura.id}/pdf`, {
        responseType: 'blob'
      });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `factura-${factura.numero}.pdf`;
      a.click();
    } catch (error) {
      console.error(error);
    }
  };

